import{_ as t,o as n,c as a,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"55. Recruitment To Vacant Position","description":"","frontmatter":{"title":"55. Recruitment To Vacant Position","eba":"Mental Health Services 2024-2028","topics":["employment","termination","staffing"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/staffing/55-recruitment-to-vacant-position.md","filePath":"ebas/mental-health/common-terms/staffing/55-recruitment-to-vacant-position.md"}'),o={name:"ebas/mental-health/common-terms/staffing/55-recruitment-to-vacant-position.md"};function r(s,e,l,c,p,m){return n(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_55-recruitment-to-vacant-position" tabindex="-1">55. Recruitment To Vacant Position <a class="header-anchor" href="#_55-recruitment-to-vacant-position" aria-label="Permalink to &quot;55. Recruitment To Vacant Position&quot;">​</a></h1><p><strong>55.1</strong> The process for advertising and filling vacancies will be as follows:</p><p><strong>(a)</strong> Each bed-based service subject to subclause 102.1 –, will have a staffing profile based on EFT of nurses.</p><p><strong>(b)</strong> Where a vacancy arises within an existing staffing profile, the responsible manager will initiate action to advertise the vacant position internally and/or externally after receiving notice of the resignation/termination.</p><p><strong>(c)</strong> The Employer shall, as soon as is practicable, (and ordinarily within 8 days (not including weekends or public holidays)) advertise all vacancies that arise where the vacancy relates to a position that but for the vacancy occurring would have been ongoing.</p><p><strong>55.2</strong> In order to support these measures, Employees intending to resign are required to give a minimum of four weeks&#39; notice, unless a shorter period is agreed to between the Employee and Employer.</p><p><strong>55.3</strong> The Employer will consult with the Employees and their unions about any changes.</p><p><strong>55.4</strong> Advertisement of position Any notice, circular or advertisement for a position regulated by this Agreement shall specify the classification, mode of employment, any mandatory qualifications or salary grade applicable.</p><p><strong>55.5</strong> Additional Measures</p><p><strong>(a)</strong> Where, despite genuine recruitment efforts the Employer has been unable to recruit to a vacant position outlined in 55.1(a), the Employer will notify the Union in writing.</p><p><strong>(b)</strong> Genuine recruitment efforts means internal and external advertising. Such efforts will be recorded in writing and available for inspection by the Unions or Union representative.</p><p>Plain language terms: filling vacancy, internal advertising, job posting.</p>',12)])])}const h=t(o,[["render",r]]);export{d as __pageData,h as default};
